# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

import os
from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import secrets
import time
from datetime import datetime, timedelta
import jwt

app = Flask(__name__)

# Configuration
SECRET_KEY = os.environ.get('SECRET_KEY', secrets.token_hex(32))
JWT_EXPIRATION_HOURS = 24
NONCE_EXPIRATION_SECONDS = 300  # 5 minutes

# In-memory storage (use Redis or database in production)
nonces = {}

# Initialize Web3
w3 = Web3()


def generate_nonce():
    """Generate a random nonce for signature verification"""
    return secrets.token_hex(16)


def cleanup_expired_nonces():
    """Remove expired nonces from storage"""
    current_time = time.time()
    expired_keys = [
        address for address, data in nonces.items()
        if current_time - data['timestamp'] > NONCE_EXPIRATION_SECONDS
    ]
    for key in expired_keys:
        del nonces[key]


def verify_signature(message, signature, expected_address):
    """
    Verify that the signature matches the expected address
    
    Args:
        message: The original message that was signed
        signature: The signature to verify
        expected_address: The Ethereum address that should have signed the message
    
    Returns:
        bool: True if signature is valid, False otherwise
    """
    try:
        # Encode the message
        message_hash = encode_defunct(text=message)
        
        # Recover the address from the signature
        recovered_address = w3.eth.account.recover_message(
            message_hash,
            signature=signature
        )
        
        # Compare addresses (case-insensitive)
        return recovered_address.lower() == expected_address.lower()
    except Exception as e:
        print(f"Signature verification error: {e}")
        return False


def create_jwt_token(address):
    """Create a JWT token for authenticated user"""
    payload = {
        'address': address.lower(),
        'exp': datetime.utcnow() + timedelta(hours=JWT_EXPIRATION_HOURS),
        'iat': datetime.utcnow()
    }
    return jwt.encode(payload, SECRET_KEY, algorithm='HS256')


def verify_jwt_token(token):
    """Verify and decode JWT token"""
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


@app.route('/api/auth/nonce', methods=['POST'])
def get_nonce():
    """
    Generate and return a nonce for the given Ethereum address
    
    Request body:
        {
            "address": "0x..."
        }
    
    Response:
        {
            "nonce": "random_hex_string",
            "message": "Sign this message to authenticate: {nonce}"
        }
    """
    cleanup_expired_nonces()
    
    data = request.get_json()
    
    if not data or 'address' not in data:
        return jsonify({'error': 'Address is required'}), 400
    
    address = data['address']
    
    # Validate Ethereum address format
    if not Web3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    # Normalize address to checksum format
    address = Web3.to_checksum_address(address)
    
    # Generate nonce
    nonce = generate_nonce()
    
    # Store nonce with timestamp
    nonces[address.lower()] = {
        'nonce': nonce,
        'timestamp': time.time()
    }
    
    message = f"Sign this message to authenticate with your wallet.\n\nNonce: {nonce}\nTimestamp: {int(time.time())}"
    
    return jsonify({
        'nonce': nonce,
        'message': message
    }), 200


@app.route('/api/auth/verify', methods=['POST'])
def verify_signature_endpoint():
    """
    Verify the signature and authenticate the user
    
    Request body:
        {
            "address": "0x...",
            "signature": "0x...",
            "message": "The message that was signed"
        }
    
    Response:
        {
            "success": true,
            "token": "jwt_token",
            "address": "0x..."
        }
    """
    cleanup_expired_nonces()
    
    data = request.get_json()
    
    if not data or 'address' not in data or 'signature' not in data or 'message' not in data:
        return jsonify({'error': 'Address, signature, and message are required'}), 400
    
    address = data['address']
    signature = data['signature']
    message = data['message']
    
    # Validate Ethereum address format
    if not Web3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    # Normalize address
    address_lower = address.lower()
    
    # Check if nonce exists for this address
    if address_lower not in nonces:
        return jsonify({'error': 'No nonce found for this address. Please request a nonce first.'}), 400
    
    nonce_data = nonces[address_lower]
    
    # Check if nonce has expired
    if time.time() - nonce_data['timestamp'] > NONCE_EXPIRATION_SECONDS:
        del nonces[address_lower]
        return jsonify({'error': 'Nonce has expired. Please request a new nonce.'}), 400
    
    # Verify that the message contains the nonce
    if nonce_data['nonce'] not in message:
        return jsonify({'error': 'Invalid message. Message must contain the nonce.'}), 400
    
    # Verify the signature
    is_valid = verify_signature(message, signature, address)
    
    if not is_valid:
        return jsonify({'error': 'Invalid signature'}), 401
    
    # Remove used nonce
    del nonces[address_lower]
    
    # Generate JWT token
    token = create_jwt_token(address)
    
    return jsonify({
        'success': True,
        'token': token,
        'address': Web3.to_checksum_address(address)
    }), 200


@app.route('/api/auth/validate', methods=['POST'])
def validate_token():
    """
    Validate a JWT token
    
    Request headers:
        Authorization: Bearer <token>
    
    Response:
        {
            "valid": true,
            "address": "0x..."
        }
    """
    auth_header = request.headers.get('Authorization')
    
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({'error': 'No token provided'}), 401
    
    token = auth_header.split(' ')[1]
    
    payload = verify_jwt_token(token)
    
    if not payload:
        return jsonify({'error': 'Invalid or expired token'}), 401
    
    return jsonify({
        'valid': True,
        'address': Web3.to_checksum_address(payload['address'])
    }), 200


@app.route('/api/protected', methods=['GET'])
def protected_route():
    """
    Example protected route that requires authentication
    
    Request headers:
        Authorization: Bearer <token>
    """
    auth_header = request.headers.get('Authorization')
    
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({'error': 'No token provided'}), 401
    
    token = auth_header.split(' ')[1]
    
    payload = verify_jwt_token(token)
    
    if not payload:
        return jsonify({'error': 'Invalid or expired token'}), 401
    
    return jsonify({
        'message': 'Access granted to protected resource',
        'address': Web3.to_checksum_address(payload['address']),
        'authenticated': True
    }), 200


